    else mid = (col / 2) ;

    for (int i = 0; i < row; ++i)
    {
        int right = col - 1; // Lỗi: Biến 'right' cần được khởi tạo lại cho mỗi hàng
        for (int j = 0; j < mid; ++j)
        {
            int temp = mat[i][j];
            mat[i][j] = mat[i][right];
            mat[i][right] = temp;
            right--;
        }
    }
}

